import { xdr, Address } from "@stellar/stellar-sdk";

const META_XDR = "";

function main() {
  const meta = xdr.TransactionMeta.fromXDR(META_XDR, "base64");
  const v4 = meta.v4();
  
  console.log("=== Transaction Meta v4 ===");
  
  v4.operations().forEach((opMeta, i) => {
    opMeta.changes().forEach((change, j) => {
      printLedgerEntryChange(change, j);
    });
  });
}

function printLedgerEntryChange(change: any, index: number) {
  const arm = change.switch().name || change.switch();
  let entry;
  if (arm === "ledgerEntryCreated" || change.switch().value === 0) {
    entry = change.created();
  } else if (arm === "ledgerEntryUpdated" || change.switch().value === 1) {
    entry = change.updated();
  } else if (arm === "ledgerEntryState" || change.switch().value === 3) {
    entry = change.state();
  }
  
  if (entry) {
    const data = entry.data();
    const dataArm = data.switch().name || data.switch();
    console.log(`Change ${index} data type: ${dataArm}`);
    if (dataArm === "contractData" || data.switch().value === 5) {
      const cData = data.contractData();
      console.log(`  Durability: ${cData.durability().name || cData.durability()}`);
      console.log(`  Key switch: ${cData.key().switch().name || cData.key().switch()}`);
      try {
        const contractIdStr = Address.fromScAddress(cData.contract()).toString();
        console.log(`  Contract ID: ${contractIdStr}`);
      } catch (e) {
        console.log(`  Failed to parse contract ID: ${e.message}`);
      }
    }
  }
}

main();
